# DiskStation Monitor — Full Project Setup Script
# Run this from inside C:\Users\LionelMosley\diskstation-monitor
# It creates every file in the correct location, then commits and pushes.

param([string]$RepoPath = "C:\Users\LionelMosley\diskstation-monitor")

Set-Location $RepoPath
Write-Host "Setting up DiskStation Monitor in $RepoPath" -ForegroundColor Cyan

function Write-File {
    param([string]$RelPath, [string]$Content)
    $FullPath = Join-Path $RepoPath $RelPath
    $Dir = Split-Path $FullPath -Parent
    if (-not (Test-Path $Dir)) { New-Item -ItemType Directory -Force -Path $Dir | Out-Null }
    [System.IO.File]::WriteAllText($FullPath, $Content, [System.Text.Encoding]::UTF8)
    Write-Host "  wrote $RelPath" -ForegroundColor Green
}

# ── .gitignore ────────────────────────────────────────────────────────────────
Write-File ".gitignore" @'
node_modules/
dist/
build/
*.tsbuildinfo
.env
.env.local
.env.*.local
npm-debug.log*
.DS_Store
Thumbs.db
.vscode/
.idea/
coverage/
.railway/
.netlify/
'@

# ── .npmrc ────────────────────────────────────────────────────────────────────
Write-File ".npmrc" @'
legacy-peer-deps=true
'@

# ── nixpacks.toml ─────────────────────────────────────────────────────────────
Write-File "nixpacks.toml" @'
[phases.setup]
nixPkgs = ["nodejs_20"]

[phases.install]
cmds = ["npm install"]

[phases.build]
cmds = ["npm run build"]

[start]
cmd = "npm start"
'@

# ── railway.toml ──────────────────────────────────────────────────────────────
Write-File "railway.toml" @'
[build]
  builder      = "nixpacks"
  buildCommand = "npm install && npm run build"

[deploy]
  startCommand            = "npm start"
  restartPolicyType       = "ON_FAILURE"
  restartPolicyMaxRetries = 3

[healthcheck]
  path    = "/health"
  timeout = 10
'@

# ── netlify.toml ──────────────────────────────────────────────────────────────
Write-File "netlify.toml" @'
[build]
  base    = "frontend"
  command = "npm run build"
  publish = "dist"

[build.environment]
  NODE_VERSION = "20"

[[redirects]]
  from   = "/*"
  to     = "/index.html"
  status = 200

[[headers]]
  for = "/assets/*"
  [headers.values]
    Cache-Control = "public, max-age=31536000, immutable"

[[headers]]
  for = "/*"
  [headers.values]
    X-Frame-Options         = "DENY"
    X-Content-Type-Options  = "nosniff"
    Referrer-Policy         = "strict-origin-when-cross-origin"
    Permissions-Policy      = "camera=(), microphone=(), geolocation=()"
    Content-Security-Policy = "default-src 'self'; script-src 'self'; style-src 'self' 'unsafe-inline' https://fonts.googleapis.com; font-src https://fonts.gstatic.com; img-src 'self' data: https://*.tile.openstreetmap.org; connect-src 'self' https://nominatim.openstreetmap.org"
'@

# ── .env.example ──────────────────────────────────────────────────────────────
Write-File ".env.example" @'
NODE_ENV=development
PORT=3001
APP_URL=http://localhost:3001
FRONTEND_URL=http://localhost:5173
DATABASE_URL=postgresql://user:password@localhost:5432/dsm_monitor
REDIS_URL=redis://localhost:6379
JWT_ACCESS_SECRET=change_me_min_32_chars_access_secret_here
JWT_REFRESH_SECRET=change_me_min_32_chars_refresh_secret_here
JWT_ACCESS_EXPIRES=15m
JWT_REFRESH_EXPIRES=7d
CREDENTIAL_ENCRYPTION_KEY=change_me_64_hex_chars_here
B2_KEY_ID=your_b2_application_key_id
B2_APPLICATION_KEY=your_b2_application_key
B2_BUCKET_NAME=dsm-monitor-storage
B2_BUCKET_ENDPOINT=https://s3.us-west-004.backblazeb2.com
BUNNY_CDN_URL=https://your-pullzone.b-cdn.net
POLL_DEFAULT_INTERVAL_SECONDS=60
POLL_OFFLINE_THRESHOLD_MISSES=5
