# ── Generate secrets and set Railway env vars ─────────────────────────────────
Write-Host "`nGenerating secrets..." -ForegroundColor Cyan

function New-RandomSecret([int]$bytes = 32) {
    $arr = New-Object byte[] $bytes
    [System.Security.Cryptography.RandomNumberGenerator]::Create().GetBytes($arr)
    return [System.Convert]::ToBase64String($arr)
}

function New-RandomHex([int]$bytes = 32) {
    $arr = New-Object byte[] $bytes
    [System.Security.Cryptography.RandomNumberGenerator]::Create().GetBytes($arr)
    return ($arr | ForEach-Object { $_.ToString("x2") }) -join ""
}

$JWT_ACCESS  = New-RandomSecret 32
$JWT_REFRESH = New-RandomSecret 32
$CRED_KEY    = New-RandomHex 32

Write-Host "  JWT_ACCESS_SECRET   = $JWT_ACCESS"  -ForegroundColor Yellow
Write-Host "  JWT_REFRESH_SECRET  = $JWT_REFRESH" -ForegroundColor Yellow
Write-Host "  CREDENTIAL_KEY      = $CRED_KEY"    -ForegroundColor Yellow

# Set Railway environment variables
Write-Host "`nSetting Railway environment variables..." -ForegroundColor Cyan
railway variables --set "NODE_ENV=production"
railway variables --set "FRONTEND_URL=https://diskstation-monitor.netlify.app"
railway variables --set "JWT_ACCESS_SECRET=$JWT_ACCESS"
railway variables --set "JWT_REFRESH_SECRET=$JWT_REFRESH"
railway variables --set "CREDENTIAL_ENCRYPTION_KEY=$CRED_KEY"
railway variables --set "JWT_ACCESS_EXPIRES=15m"
railway variables --set "JWT_REFRESH_EXPIRES=7d"
railway variables --set "POLL_DEFAULT_INTERVAL_SECONDS=60"
railway variables --set "POLL_OFFLINE_THRESHOLD_MISSES=5"
railway variables --set "POLL_AUTH_TIMEOUT_MS=10000"

